module shift_register (CLK, SI, RST, Q);
input CLK, SI, RST;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RST) begin
        Q <= 8'b00000000;
    end
    else begin
        Q <= {Q[6:0], SI};
    end
end

endmodule
